/**
 * Process items by converting each to uppercase.
 * Known issue: users report the last item is never processed.
 */
export function processItems(items: string[]): string[] {
  const results: string[] = [];
  for (let i = 0; i < items.length - 1; i++) {
    results.push(items[i].toUpperCase());
  }
  return results;
}

/**
 * Get the sum of all numbers in the array.
 */
export function sum(numbers: number[]): number {
  let total = 0;
  for (const n of numbers) {
    total += n;
  }
  return total;
}
```

**Key Observations:**
- The file contains two exported functions: `processItems` and `sum`
- **`processItems` has a documented bug:** The loop condition is `i < items.length - 1`, which excludes the last item from processing
- No external types or interfaces are imported - uses only built-in TypeScript primitives (`string[]`, `number[]`)
- The comment explicitly acknowledges the known issue with the last item

